#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i < n; ++i) {
            long long x;
            scanf("%lld", &x);
            if (x <= 101010) {
                printf("%lld\n", x * x);
            }
        }
    }
    return 0;
}

