import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        for _ in range(n):
            x = int(next(it))
            if x <= 101010:
                out.append(str(x * x))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

